import { useState } from 'react';
import API, { recommend } from '../services/api.js';

export default function Features() {
  const [query, setQuery] = useState('');
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleRecommend = async () => {
    if (!query.trim()) return;
    setLoading(true);
    try {
      const results = await recommend(query);
      setRecommendations(results);
    } catch (error) {
      console.error('Recommend error:', error);
      setRecommendations(['Error fetching recommendations. Is backend running?']);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="py-20 bg-gray-50 text-center">

      <h2 className="text-3xl font-bold mb-3">
        Core Features
      </h2>

      <p className="text-gray-500 mb-12">
        Powerful tools to simplify your research workflow
      </p>

      <div className="flex justify-center gap-8 flex-wrap">

        {/* Summary */}
        <div className="feature-card-clean">
          <h3>đź§  Summarization</h3>
          <p>Understand papers quickly with AI summaries.</p>
        </div>

        {/* Q&A */}
        <div className="feature-card-clean">
          <h3>đź’¬ Q&A</h3>
          <p>Ask questions directly from your document.</p>
        </div>

        {/* Recommend - Interactive */}
        <div className="feature-card-clean max-w-md p-6">
          <h3 className="mb-4 text-lg font-bold">đź”Ť Recommendations</h3>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Enter research topic e.g. machine learning"
            className="w-full p-3 border border-gray-300 rounded-xl mb-3 text-left focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
          />
          <button
            onClick={handleRecommend}
            disabled={loading || !query.trim()}
            className="w-full py-3 px-4 bg-gradient-to-r from-teal-500 to-blue-500 hover:from-teal-600 hover:to-blue-600 text-white font-semibold rounded-xl transition-all duration-300 shadow-lg hover:shadow-xl disabled:opacity-50 disabled:cursor-not-allowed mb-3"
          >
            {loading ? 'đź”„ Searching papers...' : 'Get Top 3 Recommendations'}
          </button>
          {recommendations.length > 0 && (
            <div className="mt-3 p-4 bg-white/80 backdrop-blur-sm rounded-xl shadow-md border border-gray-100 max-h-48 overflow-y-auto">
              <h4 className="font-bold mb-3 text-sm text-gray-800">Top Related Papers:</h4>
              <ul className="text-left text-sm space-y-2">
                {recommendations.map((title, idx) => (
                  <li key={idx} className="text-gray-900 hover:text-teal-600 transition-colors truncate" title={title}>
                    â€˘ {title}
                  </li>
                ))}
              </ul>
            </div>
          )}
          <p className="text-xs text-gray-500 mt-3 leading-relaxed">AI-powered paper discovery from OpenAlex</p>
        </div>

        {/* Idea Generator */}
        <div
          className="feature-card-clean cursor-pointer hover:shadow-lg transition max-w-sm"
          onClick={() => {
            document.getElementById("upload-section")?.scrollIntoView({
              behavior: "smooth"
            });
          }}
        >
          <h3>đź’ˇ Idea Generator</h3>
          <p>Generate innovative research and project ideas.</p>
        </div>

      </div>
    </div>
  );
}
